// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Miniature reproduction of the theme-benchmark LIBRARY query 9 shape ("members borrowing books by authors"), which
 * returned phantom rows on the native LMDB path: VALUES + BGP + disjunctive filter + NOT EXISTS with an inner date
 * comparison + OPTIONAL with a filter on the optional variable, aggregated with COUNT(DISTINCT).
 */
public class LmdbNativeLibraryQ9RegressionTest {

	private static final String LIB = "http://example.com/lib/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			for (int i = 1; i <= 2; i++) {
				IRI member = vf.createIRI(LIB, "member" + i);
				IRI loan = vf.createIRI(LIB, "loan" + i);
				IRI copy = vf.createIRI(LIB, "copy" + i);
				IRI book = vf.createIRI(LIB, "book" + i);
				IRI author = vf.createIRI(LIB, "author" + i);
				conn.add(member, RDF.TYPE, vf.createIRI(LIB, "Member"));
				conn.add(loan, RDF.TYPE, vf.createIRI(LIB, "Loan"));
				conn.add(loan, vf.createIRI(LIB, "borrowedBy"), member);
				conn.add(loan, vf.createIRI(LIB, "loanedCopy"), copy);
				conn.add(book, vf.createIRI(LIB, "hasCopy"), copy);
				conn.add(book, vf.createIRI(LIB, "writtenBy"), author);
				conn.add(author, vf.createIRI(LIB, "name"), vf.createLiteral("Author " + i));
				conn.add(book, vf.createIRI(LIB, "title"), vf.createLiteral("Title " + i));
				// every loan is overdue relative to the cutoff, so NOT EXISTS must reject every member
				conn.add(loan, vf.createIRI(LIB, "dueDate"), vf.createLiteral("2024-01-0" + i, XSD.DATE));
			}
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private long countResult(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).hasSize(1);
			return ((Literal) result.get(0).getValue("count")).longValue();
		}
	}

	private static String q9(String dueFilter) {
		return "PREFIX lib: <" + LIB + ">\n"
				+ "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
				+ "SELECT (COUNT(DISTINCT ?member) AS ?count) WHERE {\n"
				+ "  VALUES ?target { \"Author 1\" \"Author 2\" }\n"
				+ "  ?member a lib:Member .\n"
				+ "  ?loan a lib:Loan ; lib:borrowedBy ?member ; lib:loanedCopy ?copy .\n"
				+ "  ?book lib:hasCopy ?copy ; lib:writtenBy ?author .\n"
				+ "  ?author lib:name ?authorName .\n"
				+ "  FILTER(?authorName = ?target || ?authorName = \"Author 3\")\n"
				+ "  FILTER NOT EXISTS { ?loan lib:dueDate ?due .\n"
				+ "                      FILTER(" + dueFilter + ") }\n"
				+ "  OPTIONAL { ?book lib:title ?optTitle . }\n"
				+ "  FILTER(?optTitle != \"\")\n"
				+ "}";
	}

	@Test
	public void allMembersOverdueYieldsZero() {
		// both loans have dueDate < cutoff, so NOT EXISTS drops both members
		assertThat(countResult(q9("?due < \"2024-01-10\"^^xsd:date"))).isEqualTo(0);
	}

	@Test
	public void noMemberOverdueYieldsTwo() {
		// cutoff before both due dates: NOT EXISTS keeps both members
		assertThat(countResult(q9("?due < \"2024-01-01\"^^xsd:date"))).isEqualTo(2);
	}

	@Test
	public void oneMemberOverdueYieldsOne() {
		// cutoff between the two due dates
		assertThat(countResult(q9("?due < \"2024-01-02\"^^xsd:date"))).isEqualTo(1);
	}
}
